class Solution {
public:
    char kthCharacter(long long k, vector<int>& operations) {
        long long length = 1;
        long long increment = 0;
        for (int op : operations) {
            if (op == 0) {
                length *= 2;
            } else {
                length *= 2;
                increment++;
            }
            if (length >= k) break;
        }
        k -= 1; // Convert to 0-based index
        long long pos = k % length; // Find position within current string
        long long offset = k / length; // Determine which half of the string to look at
        char baseChar = 'a' + (increment % 26); // Character base due to increments
        if (offset == 0) {
            return baseChar + (pos % 26); // Return character directly
        } else {
            return baseChar + ((pos + 26 - offset) % 26); // Adjust for offset
        }
    }
};
```
